/**
 * GoTable (native) — stub implementation.
 *
 * The Table component is web-only at this stage.
 * This stub ensures the library builds without errors on React Native
 * and provides a clear developer warning instead of silently rendering nothing.
 */
import {
    createContext,
    useContext,
} from "react";
import type {
    IDataTableContextValues,
    IDataTableProps,
} from "@lmb/kitsconcerto-types";

// Re-export context so useTable() works on native without crashing
export const TableContext = createContext<IDataTableContextValues>(
    {} as IDataTableContextValues,
);

export function useTable<T extends Record<string, any> = any>() {
    return useContext(TableContext) as IDataTableContextValues<T>;
}

// Size/font constants kept here so any shared code that imports them compiles on native
export const sizeMapping = {
    small: "5px",
    normal: "10px",
    large: "15px",
} as const;

export const fontSizeMapping = {
    small: "13px",
    normal: "16px",
    large: "20px",
} as const;

const Datatable = <T extends Record<string, any> = any,>(_props: IDataTableProps<T>) => {
    if (typeof __DEV__ !== "undefined" && __DEV__) {
        console.warn(
            "[GoTable] The Table component is not available on React Native. " +
            "It is a web-only component. A native implementation is planned for a future release.",
        );
    }
    return null;
};

export default Datatable;
